#include<bits/stdc++.h>
using namespace std;
int n,m;
__int128 dp[101][101],base[101];
int a[101][101];
void write(__int128 x,int flag=1)
{
    if(x==0&&flag==1)
    {
        printf("0");
        return;
    }
    if(x==0)
    {
        return;
    }
    write(x/10,0);
    printf("%d",(int)(x%10));
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
        }
    }
    base[0]=1;
    for(int i=1;i<=m+4;i++)
    {
        base[i]=base[i-1]*2;
    }
    __int128 ans=0;
    for(int x=1;x<=n;x++)
    {
        memset(dp,0,sizeof(dp));
        for(int l=1;l<=m;l++)
        {
            for(int r=m;r>=l;r--)
            {
                dp[l][r]=max({dp[l][r],dp[l-1][r]+a[x][l-1]*base[m-r+l-1],dp[l][r+1]+a[x][r+1]*base[m-r+l-1]});
            }
        }
        __int128 max1=-1;
        for(int i=1;i<=m;i++)
        {
            max1=max(max1,dp[i][i]+base[m]*a[x][i]);
        }
        ans+=max1;
    }
    write(ans);
    return 0;
}
